using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        var entity = modelBuilder.Entity<Product>();
        entity.ToContainer("Products");

        // BREAKING CHANGE 1: Discriminator property renamed from "Discriminator" to "$type".
        // Pin the old name so existing 500K documents and raw SQL queries keep working.
        entity.HasDiscriminator<string>("Discriminator");

        // BREAKING CHANGE 2: id format changed from "EntityType|Key" to just "Key".
        // EF Core 8 synthesized a shadow "__id" property with value "Product|<key>".
        // Re-create that shadow property so reads/writes match existing documents.
        entity.Property<string>("__id")
